// Simulated in-memory product catalog.
// In production this would query a real database; the module-level state
// is updated asynchronously by syncCatalog() to simulate upstream changes.
let products = [
  { id: 1, sku: 'LAP-001', name: 'UltraBook Pro 16',       price: 1999, inventory: 12,  category: 'Laptops',    status: 'active',       lastUpdated: '2026-07-16T10:00:00Z' },
  { id: 2, sku: 'PHN-023', name: 'Galaxy S30',              price: 999,  inventory: 48,  category: 'Phones',     status: 'active',       lastUpdated: '2026-07-16T10:00:00Z' },
  { id: 3, sku: 'TAB-007', name: 'Tab Ultra 14',            price: 749,  inventory: 0,   category: 'Tablets',    status: 'discontinued', lastUpdated: '2026-07-16T10:00:00Z' },
  { id: 4, sku: 'AUD-112', name: 'Noise-Cancelling Pro',    price: 349,  inventory: 235, category: 'Audio',      status: 'active',       lastUpdated: '2026-07-16T10:00:00Z' },
  { id: 5, sku: 'WCH-034', name: 'SportWatch 5',            price: 399,  inventory: 88,  category: 'Wearables',  status: 'active',       lastUpdated: '2026-07-16T10:00:00Z' },
  { id: 6, sku: 'MON-019', name: '4K HDR Monitor 32"',      price: 1299, inventory: 31,  category: 'Monitors',   status: 'active',       lastUpdated: '2026-07-16T10:00:00Z' },
  { id: 7, sku: 'KEY-055', name: 'Mechanical Keyboard TKL', price: 179,  inventory: 0,   category: 'Accessories', status: 'backorder',    lastUpdated: '2026-07-16T10:00:00Z' },
  { id: 8, sku: 'MSE-022', name: 'Ergo Trackball',          price: 89,   inventory: 412, category: 'Accessories', status: 'active',       lastUpdated: '2026-07-16T10:00:00Z' },
];

export async function getAllProducts() {
  // Simulate a lightweight database read
  await new Promise(resolve => setTimeout(resolve, 80));
  return products;
}

/**
 * Simulates a long-running catalog sync from an upstream ERP/PIM system.
 * Updates pricing, inventory, and availability in the background.
 *
 * In production this would enqueue a job (e.g. via a message queue / job
 * worker) and return immediately.  The worker processes thousands of SKUs
 * and eventually updates the database, after which cache revalidation
 * ensures downstream views see fresh data.
 */
export async function syncCatalog() {
  // Simulate the network / compute latency of a real sync job
  await new Promise(resolve => setTimeout(resolve, 3000));

  const now = new Date().toISOString();

  // Mutate pricing and inventory to simulate an upstream data refresh
  products = products.map(p => {
    const priceDelta = Math.round(Math.random() * 60 - 20);   // -20 .. +40
    const invDelta   = Math.round(Math.random() * 30 - 8);     // -8  .. +22
    return {
      ...p,
      price:       Math.max(1, p.price + priceDelta),
      inventory:   Math.max(0, p.inventory + invDelta),
      lastUpdated: now,
    };
  });

  // Occasionally simulate a new SKU arriving from upstream
  if (Math.random() > 0.6) {
    const id  = products.length + 1;
    const now = new Date().toISOString();
    products = [
      ...products,
      {
        id,
        sku: `NEW-SKU-${String(id).padStart(3, '0')}`,
        name: `Catalog Item ${id}`,
        price:       Math.round(Math.random() * 1500 + 50),
        inventory:   Math.round(Math.random() * 200),
        category:    ['Accessories', 'Audio', 'Monitors'][Math.floor(Math.random() * 3)],
        status:      'active',
        lastUpdated: now,
      },
    ];
  }
}

