import { unstable_cache } from 'next/cache';
import { revalidateTag } from 'next/cache';
import { getAllProducts, syncCatalog } from '@/lib/db';
import { CatalogContent } from './catalog-content';

export const dynamic = 'force-static';

// Cache the product list with the "products" tag so all catalog views share
// the same cache entry and a single revalidateTag call refreshes them all.
const getCachedProducts = unstable_cache(
  async () => getAllProducts(),
  ['admin-catalog-products'],
  { tags: ['products'] },
);

export default async function AdminCatalogPage() {
  const products = await getCachedProducts();

  /**
   * Inline Server Action — renders as a regular <form> POST so the browser
   * handles submission natively without client-side JS.
   *
   * 1. Fire syncCatalog() without awaiting it (background I/O).
   * 2. Immediately invalidate the "products" cache tag so the next read
   *    (after the sync settles) fetches fresh data.
   * 3. Return a status object the client component can display.
   */
  async function syncAction() {
    'use server';

    // Don't await — let the sync complete in the background.
    // eslint-disable-next-line @typescript-eslint/no-floating-promises
    syncCatalog();

    // Mark the cached catalog as stale — subsequent fetches with the
    // "products" tag will revalidate in the background (stale-while-revalidate).
    revalidateTag('products');

    return {
      success: true,
      message: 'Catalog sync started — product data will refresh shortly.',
    };
  }

  return (
    <CatalogContent
      products={products}
      syncAction={syncAction}
    />
  );
}

'use client';

import { useActionState } from 'react';

interface Product {
  id: number;
  sku: string;
  name: string;
  price: number;
  inventory: number;
  category: string;
  status: string;
  lastUpdated: string;
}

interface SyncState {
  success: boolean;
  message: string;
}

export function CatalogContent({
  products,
  syncAction,
}: {
  products: Product[];
  syncAction: (formData: FormData) => Promise<SyncState>;
}) {
  const [state, formAction, pending] = useActionState<SyncState | null, FormData>(
    async (_prev, formData) => syncAction(formData),
    null,
  );

  return (
    <div className="catalog-page">
      <header className="catalog-header">
        <div>
          <h1>Product Catalog</h1>
          <p className="product-count">{products.length} products</p>
        </div>

        <form action={formAction}>
          <button
            type="submit"
            disabled={pending}
            className={`sync-btn${pending ? ' syncing' : ''}`}
          >
            {pending ? 'Syncing…' : 'Sync latest catalog'}
          </button>
        </form>
      </header>

      {state?.success && (
        <div className="toast toast-success" role="status">
          <span>{state.message}</span>
          <button
            className="toast-close"
            onClick={(e) => {
              (e.currentTarget.parentElement as HTMLDivElement).style.display = 'none';
            }}
            aria-label="Dismiss"
          >
            &times;
          </button>
        </div>
      )}

      <div className="catalog-table-wrapper">
        <table className="catalog-table">
          <thead>
            <tr>
              <th>SKU</th>
              <th>Name</th>
              <th>Category</th>
              <th className="num">Price</th>
              <th className="num">Inventory</th>
              <th>Status</th>
              <th>Last Updated</th>
            </tr>
          </thead>
          <tbody>
            {products.length === 0 ? (
              <tr>
                <td colSpan={7} className="empty-row">
                  No products found.
                </td>
              </tr>
            ) : (
              products.map((p) => (
                <tr key={p.id}>
                  <td className="sku">{p.sku}</td>
                  <td className="name">{p.name}</td>
                  <td>{p.category}</td>
                  <td className="num">${p.price.toLocaleString()}</td>
                  <td className="num">
                    <span
                      className={
                        p.inventory === 0
                          ? 'inv-zero'
                          : p.inventory < 20
                            ? 'inv-low'
                            : ''
                      }
                    >
                      {p.inventory}
                    </span>
                  </td>
                  <td>
                    <span className={`status-badge status-${p.status}`}>
                      {p.status}
                    </span>
                  </td>
                  <td className="date-cell">
                    {new Date(p.lastUpdated).toLocaleString()}
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      <style>{`
        .catalog-page {
          max-width: 1120px;
          margin: 0 auto;
          padding: 2rem 1.5rem;
          font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, sans-serif;
        }
        .catalog-header {
          display: flex;
          justify-content: space-between;
          align-items: flex-end;
          margin-bottom: 1.5rem;
          flex-wrap: wrap;
          gap: 1rem;
        }
        .catalog-header h1 {
          margin: 0;
          font-size: 1.75rem;
          font-weight: 600;
        }
        .product-count {
          margin: 0.25rem 0 0;
          color: #666;
          font-size: 0.875rem;
        }
        .sync-btn {
          padding: 0.6rem 1.25rem;
          background: #2563eb;
          color: #fff;
          border: none;
          border-radius: 6px;
          font-size: 0.875rem;
          font-weight: 500;
          cursor: pointer;
          white-space: nowrap;
          transition: background 0.15s, opacity 0.15s;
        }
        .sync-btn:hover:not(:disabled) { background: #1d4ed8; }
        .sync-btn:disabled { opacity: 0.6; cursor: not-allowed; }
        .sync-btn.syncing { background: #6366f1; }

        .toast {
          padding: 0.75rem 1rem;
          border-radius: 6px;
          margin-bottom: 1rem;
          display: flex;
          justify-content: space-between;
          align-items: center;
          font-size: 0.875rem;
          animation: fadeIn 0.2s ease;
        }
        .toast-success {
          background: #ecfdf5;
          border: 1px solid #a7f3d0;
          color: #065f46;
        }
        .toast-close {
          background: none;
          border: none;
          font-size: 1.25rem;
          cursor: pointer;
          color: inherit;
          padding: 0 0 0 1rem;
          line-height: 1;
        }
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(-4px); }
          to   { opacity: 1; transform: translateY(0); }
        }

        .catalog-table-wrapper {
          overflow-x: auto;
          border: 1px solid #e2e8f0;
          border-radius: 8px;
        }
        .catalog-table {
          width: 100%;
          border-collapse: collapse;
          font-size: 0.875rem;
        }
        .catalog-table th {
          background: #f8fafc;
          padding: 0.75rem 1rem;
          text-align: left;
          font-weight: 600;
          color: #334155;
          border-bottom: 2px solid #e2e8f0;
          white-space: nowrap;
        }
        .catalog-table td {
          padding: 0.75rem 1rem;
          border-bottom: 1px solid #f1f5f9;
          color: #1e293b;
        }
        .catalog-table tbody tr:hover {
          background: #f8fafc;
        }
        .catalog-table th.num,
        .catalog-table td.num {
          text-align: right;
          font-variant-numeric: tabular-nums;
        }
        td.sku {
          font-family: 'SF Mono', 'Cascadia Code', monospace;
          font-size: 0.8125rem;
          color: #64748b;
        }
        td.name { font-weight: 500; }
        td.date-cell { white-space: nowrap; color: #64748b; font-size: 0.8125rem; }
        .empty-row {
          text-align: center;
          padding: 3rem 1rem;
          color: #94a3b8;
        }

        .inv-zero { color: #dc2626; font-weight: 600; }
        .inv-low  { color: #d97706; font-weight: 500; }

        .status-badge {
          display: inline-block;
          padding: 0.15rem 0.5rem;
          border-radius: 9999px;
          font-size: 0.75rem;
          font-weight: 500;
          text-transform: capitalize;
        }
        .status-active       { background: #dcfce7; color: #166534; }
        .status-discontinued { background: #fef2f2; color: #991b1b; }
        .status-backorder    { background: #fef9c3; color: #854d0e; }
      `}</style>
    </div>
  );
}

